  goran_nilsson:{name:"Göran Nilsson",role:"Far",born:"1956-05-26",status:"confirmed",facts:[["Maka","Gerd Bengtsson"],["Barn","Axel och Ebba"],["Mor","Elsa Helena"],["Far","Nils Stig Henning Nilsson"]],story:["Göran Nilsson föds 26 maj 1956. Han är gift med Gerd Bengtsson och tillsammans får de barnen Axel och Ebba.","På pappas sida är hans mor Elsa Helena, född 24 september 1920 i Torpa, och hans far Nils Stig Henning Nilsson, född 13 maj 1924."],parents:["elsa_helena_karlsson","nils_stig_henning_nilsson"],children:["axel_nilsson","ebba_nilsson"]},

  nils_stig_henning_nilsson:{name:"Nils Stig Henning Nilsson",role:"Farfar",born:"1924-05-13",status:"working",place:"Årstad / farfars sida",facts:[["Föräldrar","Nils Birger Gustafsson och Alma Sofia Nilsson"],["Syskon","Ingrid Linnéa, Karl Rune Ingvar, Sonja Gunnel, Sven Erik Gustaf, Lars Olof Bertil och Nils Ove Sjunne"],["Källstatus","Namn, födelsedatum och hushållsrelationer belagda i hushållsöversikt/index; födelsenotis behöver kontrolleras"],["Kommentar","Tidigare preliminär avläsning 1931-05-19 ersätts av 1924-05-13"]],story:["Nils Stig Henning Nilsson är Göran Nilssons far och därmed Axels farfar.","Han förs med födelsedatum 13 maj 1924 enligt den senaste hushållsöversikten. Samma person förekommer två gånger i materialet med samma födelsedatum, vilket behandlas som en indexdubblett och inte som två personer.","Hans föräldrar är Nils Birger Gustafsson och Alma Sofia, född Nilsson. Födelsenotis/originalkälla ska kontrolleras för att låsa födelseförsamling och dopuppgift."],parents:["nils_birger_gustafsson","alma_sofia_nilsson"],children:["goran_nilsson"]},
  nils_birger_gustafsson:{name:"Nils Birger Gustafsson",role:"Farfars far",born:"1896-07-03",status:"confirmed",place:"Fjellalunda / Årstad",facts:[["Döpt","1896-07-05"],["Födelseförsamling","Årstad (N)"],["Vigsel","1924-02-16 i Årstad med Alma Sofia Nilsson"],["Bostadsorter","Fjellalunda; Årstad; Sannarps Torp/Årstad 24:1; Stockarne; Bengtstorp; Smedjegård/Hästhagen/Slättaled"],["Föräldrar","Gustaf Henning Johansson och Augusta Olivia Larsdotter"],["Källstatus","Födelse, dop och föräldrar originalkällbekräftade; boendehistorik registerbekräftad"]],story:["Nils Birger Gustafsson föds 3 juli 1896 i Årstad och döps 5 juli. Födelsenotisen anger föräldrarna Gustaf Henning Johansson och Augusta Olivia Larsdotter i Fjellalunda.","Han vigs 16 februari 1924 i Årstad med Alma Sofia Nilsson. Paret får barnen Nils Stig Henning, Ingrid Linnéa, Karl Rune Ingvar, Sonja Gunnel, Sven Erik Gustaf, Lars Olof Bertil och Nils Ove Sjunne.","ArkivDigital-posterna visar honom i Årstad över flera perioder, bland annat Fjellalunda, Sannarps Torp/Stockarne, Bengtstorp och Smedjegård/Hästhagen/Slättaled. Rörelsemönstret är registerbekräftat och kan senare fördjupas i originalbilder."],timeline:[["1896-07-03","Föds i Årstad, kopplad till Fjellalunda."],["1896-07-05","Döps."],["1905-1920","Finns i hushållet i Fjellalunda."],["1924-02-16","Vigs med Alma Sofia Nilsson i Årstad."],["1930-1948","Förekommer i flera Årstad-poster, bland annat Sannarps Torp/Stockarne och Bengtstorp."]],parents:["gustaf_henning_johansson","augusta_olivia_larsdotter"],children:["nils_stig_henning_nilsson","ingrid_linnea_nilsson","karl_rune_ingvar_nilsson","sonja_gunnel_nilsson","sven_erik_gustaf_nilsson","lars_olof_bertil_nilsson","nils_ove_sjunne_nilsson"]},
  alma_sofia_nilsson:{name:"Alma Sofia Nilsson",role:"Farfars mor",born:"1900-04-04",status:"working",place:"Årstad",facts:[["Vigsel","1924-02-16 i Årstad med Nils Birger Gustafsson"],["Barn","Nils Stig Henning, Ingrid Linnéa, Karl Rune Ingvar, Sonja Gunnel, Sven Erik Gustaf, Lars Olof Bertil och Nils Ove Sjunne"],["Källstatus","Namn, flicknamn och födelsedatum belagda i hushållsöversikt; födelseort och originalkälla behöver kontrolleras"],["Kommentar","Korrigerar tidigare preliminär avläsning 1900-07-04"]],story:["Alma Sofia Nilsson föds enligt hushållsöversikten 4 april 1900. Födelseort och födelsenotis är ännu inte kontrollerade.","Hon vigs 16 februari 1924 i Årstad med Nils Birger Gustafsson. Båda hänvisas i vigselmaterialet till församlingsbokssida 393, vilket är ett viktigt nästa steg för hushållet efter vigseln."],parents:[],children:["nils_stig_henning_nilsson","ingrid_linnea_nilsson","karl_rune_ingvar_nilsson","sonja_gunnel_nilsson","sven_erik_gustaf_nilsson","lars_olof_bertil_nilsson","nils_ove_sjunne_nilsson"]},
