  gustaf_henning_johansson:{name:"Gustaf Henning Johansson",role:"Nils Birgers far",born:"1863-07-15",status:"confirmed",place:"Årstad / Fjellalunda",facts:[["Döpt","1863-07-19"],["Födelseförsamling","Årstad"],["Yrke/titel","Statdräng i Fjellalunda; senare torpare"],["Vigsel","troligen 1888-10-26 med Augusta Olivia Larsdotter, behöver kontrolleras i vigselbok"],["Föräldrar","Johannes Andersson och Inger Hansdotter"],["Källa","Gustaf Hennings födelsenotis samt Nils Birgers födelsenotis"]],story:["Gustaf Henning Johansson föds 15 juli 1863 i Årstad och döps 19 juli. Födelsenotisen anger föräldrarna torparen Johannes Andersson och Inger Hansdotter.","Han förekommer som dräng i Gödastorp Ödgärdet i Skrea före hushållet med Augusta Olivia Larsdotter, och senare i Årstad/Fjellalunda. I Fjellalunda-hushållet står han som statdräng och senare på sida 425 som torpare.","Han och Augusta Olivia Larsdotter får flera barn, däribland Nils Birger Gustafsson som för farfarslinjen vidare."],timeline:[["1863-07-15","Föds i Årstad."],["1863-07-19","Döps."],["ca 1881-1882","Förekommer som dräng i Gödastorp Ödgärdet, Skrea, med flyttspår mot Årstad."],["trol. 1888-10-26","Trolig vigsel med Augusta Olivia Larsdotter enligt hushållslängd."],["1896-07-03","Sonen Nils Birger föds i Årstad."],["1905-1920","Familjen återfinns i Fjellalunda."]],parents:["johannes_andersson_arstad","inger_hansdotter_arstad"],children:["jenny_serafia_gustafsdotter","anna_josefina_gustafsdotter","selma_clarentia_gustafsdotter","hilma_elisabeth_gustafsdotter","alice_maria_gustafsdotter","nils_birger_gustafsson","karl_leonard_gustafsson","agnes_gunhild_gustafsdotter","ingeborg_natalia_gustafsdotter"]},
  augusta_olivia_larsdotter:{name:"Augusta Olivia Larsdotter",role:"Nils Birgers mor",born:"1863-01-04",status:"confirmed",place:"Stafsinge / Fjellalunda, Årstad",facts:[["Födelseort","Stafsinge"],["Vigsel","troligen 1888-10-26 med Gustaf Henning Johansson, behöver kontrolleras i vigselbok"],["Källstatus","Namn, födelsedatum, födelseort och hushåll originalkällbekräftade i Årstad AIIa:3"],["Nästa steg","Identifiera föräldrar bakåt"]],story:["Augusta Olivia Larsdotter föds 4 januari 1863 i Stafsinge enligt hushållslängden.","Hon är hustru till Gustaf Henning Johansson och mor till Nils Birger Gustafsson. Hennes föräldrar bakåt är ännu inte kartlagda i denna gren.","Hushållet i Fjellalunda visar henne tillsammans med Gustaf Henning och barnen. Vigseluppgiften i hushållslängden ser ut att vara 1888-10-26 men bör kontrolleras i vigselbok."],parents:[],children:["jenny_serafia_gustafsdotter","anna_josefina_gustafsdotter","selma_clarentia_gustafsdotter","hilma_elisabeth_gustafsdotter","alice_maria_gustafsdotter","nils_birger_gustafsson","karl_leonard_gustafsson","agnes_gunhild_gustafsdotter","ingeborg_natalia_gustafsdotter"]},
